module top_module(
    input [3:0] A,
    input [3:0] B,
    input [2:0] control,
    output reg [3:0] invalid_result
);always @(*) begin
        case (control)
            3'b000: invalid_result = A + B;
            3'b001: invalid_result = A - B;
            3'b010: invalid_result = A & B;
            3'b011: invalid_result = A | B;
            default: invalid_result = 4'b0000;
        endcase
    end

endmodule
